import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.B72_uj9U.js";const c=JSON.parse('{"title":"服装行业审核前文件请求清单（GAR-AUD-001）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/garment/audit-checklist.md","filePath":"zh/industry/garment/audit-checklist.md"}'),h={name:"zh/industry/garment/audit-checklist.md"};function o(l,t,i,n,_,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="服装行业审核前文件请求清单-gar-aud-001" tabindex="-1">服装行业审核前文件请求清单（GAR-AUD-001） <a class="header-anchor" href="#服装行业审核前文件请求清单-gar-aud-001" aria-label="Permalink to &quot;服装行业审核前文件请求清单（GAR-AUD-001）&quot;">​</a></h1><blockquote><p><strong>发送时机：</strong> 现场审核前 <strong>4周</strong> 发送给工厂</p><p><strong>目的：</strong> 在进厂前完成文件预审，将现场时间集中于工人访谈、设施巡查和交叉核验。文件不完整的，审核可能推迟。</p></blockquote><hr><p><strong>工厂信息确认</strong></p><p>请在提交文件时同时确认以下信息：</p><ul><li>工厂实际生产地址（GPS坐标）：___________</li><li>审核当天预计在厂工人人数：___________</li><li>是否存在分包工厂（如有请列出）：___________</li><li>当前执行的客户行为准则（SCoC）版本：___________</li></ul><hr><h2 id="模块一-合法经营资质" tabindex="-1">模块一　合法经营资质 <a class="header-anchor" href="#模块一-合法经营资质" aria-label="Permalink to &quot;模块一　合法经营资质&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>1.1</td><td>营业执照</td><td>有效期内，与工厂实际生产地址一致</td><td>□</td></tr><tr><td>1.2</td><td>建筑使用许可证</td><td>确认批准用途（工业/商业）与实际一致</td><td>□</td></tr><tr><td>1.3</td><td>规划/建设许可证</td><td>如有扩建、加建，须提供对应批准文件</td><td>□</td></tr><tr><td>1.4</td><td>消防验收证明</td><td>须为当前楼层/布局的有效证明</td><td>□</td></tr><tr><td>1.5</td><td>安全生产许可证（如适用）</td><td>特定行业（涉及危化品）必须</td><td>□</td></tr><tr><td>1.6</td><td>环保排污许可证</td><td>湿法加工（染整）工厂必须</td><td>□</td></tr></tbody></table><hr><h2 id="模块二-劳工与人事档案" tabindex="-1">模块二　劳工与人事档案 <a class="header-anchor" href="#模块二-劳工与人事档案" aria-label="Permalink to &quot;模块二　劳工与人事档案&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>2.1</td><td>全体员工名单</td><td>包含姓名、性别、年龄/出生日期、入职日期、工种、合同类型（正式/派遣/实习）</td><td>□</td></tr><tr><td>2.2</td><td>劳动合同样本</td><td>正式员工合同样本×1、劳务派遣合同样本×1（如有）</td><td>□</td></tr><tr><td>2.3</td><td>最近12个月工资记录</td><td>按月，含基本工资、加班费、各项扣除、实发工资，须能与出勤记录交叉核验</td><td>□</td></tr><tr><td>2.4</td><td>最近12个月出勤打卡记录</td><td>原始电子数据优先（非手工汇总表），包含每日上下班时间</td><td>□</td></tr><tr><td>2.5</td><td>社保缴纳证明</td><td>最近3个月，须显示缴纳人数与员工名单基本一致</td><td>□</td></tr><tr><td>2.6</td><td>年龄证明核验记录</td><td>工厂如何核验员工年龄，是否保留证件副本</td><td>□</td></tr><tr><td>2.7</td><td>工资标准公示</td><td>当前适用的最低工资标准，工厂如何告知工人</td><td>□</td></tr><tr><td>2.8</td><td>加班审批制度</td><td>书面加班政策，加班如何申请/批准/记录</td><td>□</td></tr><tr><td>2.9</td><td>纪律处分记录</td><td>过去12个月（如有），用于识别是否存在惩罚性扣薪</td><td>□</td></tr><tr><td>2.10</td><td>外籍劳工档案（如有）</td><td>工作许可证、招募合同、签证记录</td><td>□</td></tr></tbody></table><hr><h2 id="模块三-建筑与消防安全" tabindex="-1">模块三　建筑与消防安全 <a class="header-anchor" href="#模块三-建筑与消防安全" aria-label="Permalink to &quot;模块三　建筑与消防安全&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>3.1</td><td>建筑结构安全评估报告</td><td>由持证结构工程师出具，5年内有效</td><td>□</td></tr><tr><td>3.2</td><td>电气系统检测报告</td><td>2年内有效</td><td>□</td></tr><tr><td>3.3</td><td>消防设施检测记录</td><td>灭火器、喷淋、报警器，12个月内</td><td>□</td></tr><tr><td>3.4</td><td>消防演练记录</td><td>近12个月，含日期、参与人数、演练结果</td><td>□</td></tr><tr><td>3.5</td><td>工厂平面图</td><td>显示疏散通道、紧急出口、消防设施位置</td><td>□</td></tr><tr><td>3.6</td><td>重型设备安装批准文件</td><td>发电机、空压机等安装的结构承重评估（如适用）</td><td>□</td></tr><tr><td>3.7</td><td>事故记录</td><td>近3年工伤及财产损失事故记录</td><td>□</td></tr></tbody></table><hr><h2 id="模块四-化学品管理-染整-后整理工厂适用" tabindex="-1">模块四　化学品管理（染整/后整理工厂适用） <a class="header-anchor" href="#模块四-化学品管理-染整-后整理工厂适用" aria-label="Permalink to &quot;模块四　化学品管理（染整/后整理工厂适用）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>4.1</td><td>化学品清单（Chemical Inventory）</td><td>所有在用化学品，含CAS号、供应商</td><td>□</td></tr><tr><td>4.2</td><td>安全数据表（SDS/MSDS）</td><td>与化学品清单对应，须为中文版</td><td>□</td></tr><tr><td>4.3</td><td>ZDHC MRSL合规声明或检测报告</td><td>由ZDHC认可实验室出具</td><td>□</td></tr><tr><td>4.4</td><td>废水检测报告</td><td>近6个月，由资质机构检测</td><td>□</td></tr><tr><td>4.5</td><td>危险废物转移联单</td><td>近12个月，含处置单位资质证明</td><td>□</td></tr><tr><td>4.6</td><td>化学品储存区照片</td><td>现状照片（提交文件时拍摄）</td><td>□</td></tr></tbody></table><hr><h2 id="模块五-供应链透明度" tabindex="-1">模块五　供应链透明度 <a class="header-anchor" href="#模块五-供应链透明度" aria-label="Permalink to &quot;模块五　供应链透明度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>5.1</td><td>分包工厂名单</td><td>全部分包商，含地址、联系方式、主要产品</td><td>□</td></tr><tr><td>5.2</td><td>面料主要供应商名单</td><td>前5大面料供应商，含地址</td><td>□</td></tr><tr><td>5.3</td><td>棉花/棉纱溯源文件</td><td>产地证明，如涉及美国市场须符合UFLPA要求</td><td>□</td></tr><tr><td>5.4</td><td>原棉采购合同样本</td><td>用于核验供应商声明</td><td>□</td></tr></tbody></table><hr><h2 id="模块六-管理体系与历史审核" tabindex="-1">模块六　管理体系与历史审核 <a class="header-anchor" href="#模块六-管理体系与历史审核" aria-label="Permalink to &quot;模块六　管理体系与历史审核&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>6.1</td><td>SA8000 / BSCI / WRAP 认证书</td><td>如有，须在有效期内</td><td>□</td></tr><tr><td>6.2</td><td>最近一次外部审核报告</td><td>不限机构，12个月内</td><td>□</td></tr><tr><td>6.3</td><td>CAP整改计划进展</td><td>针对最近审核发现的未关闭NCR</td><td>□</td></tr><tr><td>6.4</td><td>工人申诉/举报记录</td><td>近12个月（含零记录说明）</td><td>□</td></tr><tr><td>6.5</td><td>管理层架构图</td><td>合规/HR/EHS负责人标注</td><td>□</td></tr></tbody></table><hr><h2 id="文件提交说明" tabindex="-1">文件提交说明 <a class="header-anchor" href="#文件提交说明" aria-label="Permalink to &quot;文件提交说明&quot;">​</a></h2><ul><li>所有文件以 <strong>PDF 格式</strong>提交，命名规则：<code>[工厂名称]_[文件类型]_[日期].pdf</code></li><li>提交截止日期：<strong>审核日期前14个工作日</strong></li><li>提交方式：[指定安全文件共享平台链接]</li><li>如文件不可用或有特殊情况，请提前说明原因</li></ul><p><strong>文件不完整将导致审核推迟。</strong></p>',28)])])}const u=d(h,[["render",o]]);export{c as __pageData,u as default};
